public class ExceptionTest {
    static int divide(int a, int b) {
        if (b == 0) throw new ArithmeticException("div by zero");
        return a / b;
    }
    // Simulating assertThrows
    static <T extends Throwable> T assertThrows(Class<T> clazz, Runnable r) {
        try { r.run(); throw new AssertionError("Expected exception"); }
        catch (Throwable t) {
            if (!clazz.isInstance(t)) throw new AssertionError("Wrong type");
            return clazz.cast(t);
        }
    }
    public static void main(String[] args) {
        ArithmeticException ex = assertThrows(ArithmeticException.class, () -> divide(5, 0));
        System.out.println(ex.getMessage());
        System.out.println(divide(10, 2));
    }
}
